const s=e=>{e.data("videoInitialization",(t,i=!0)=>({isPlaying:!1,embedUrl:`https://www.youtube.com/embed/${t}`,iframeParam:"?autoplay=1",get videoUrl(){return i?`${this.embedUrl}${this.iframeParam}`:t},play(){this.isPlaying=!0,this.$nextTick(()=>{this.$refs.videoElement.setAttribute("src",this.videoUrl)})},stop(){this.isPlaying=!1,this.$nextTick(()=>{this.$refs.videoElement.setAttribute("src","")})}}))};export{s as default};
